#include<iostream>
#include<algorithm>
using namespace std;
const int MAXN=1e5+5;
struct Node{int a,b;}a[MAXN];
bool cmp(Node s, Node t){return s.b<t.b;}
int n,ans=0;
int main(void){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i].a>>a[i].b;
    sort(a+1,a+1+n,cmp);
    int left=1,right=n;
    while(left<=right){
		ans=max(a[left].b+a[right].b,ans);
        if(a[left].a>a[right].a)a[left].a-=a[right].a,right--;
        else if(a[left].a<a[right].a)a[right].a-=a[left].a,left++;
        else left++,right--;
    }cout<<ans;
    return false;
}
